import React, { useState, useMemo, useEffect } from 'react';
import { useSearchParams } from 'react-router-dom';
import Header from '../components/Header';
import Footer from '../components/Footer';
import { ChevronDown, ChevronLeft, ChevronRight, SlidersHorizontal } from 'lucide-react';
import { Dialog, DialogContent, DialogTitle } from '@shadcn/ui';

const AllProductsPage = () => {
  const [sortBy, setSortBy] = useState('newest');
  const [selectedCategory, setSelectedCategory] = useState('all');
  const [currentPage, setCurrentPage] = useState(1);
  const [showModal, setShowModal] = useState(false);
  const [selectedProduct, setSelectedProduct] = useState(null);
  const productsPerPage = 12;
  const [searchParams] = useSearchParams();

  // Dados simulados dos produtos - depois virão da API
  const products = [
    { id: 1, name: "Camiseta Oversized", price: 129.90, images: ["https://via.placeholder.com/400x400", "https://via.placeholder.com/400x400", "https://via.placeholder.com/400x400", "https://via.placeholder.com/400x400"], category: "roupas", sizes: ["P", "M", "G", "GG"], colors: ["Preto", "Branco", "Cinza", "Azul"] },
    { id: 2, name: "Calça Cargo", price: 259.90, images: ["https://via.placeholder.com/400x400", "https://via.placeholder.com/400x400", "https://via.placeholder.com/400x400", "https://via.placeholder.com/400x400"], category: "roupas", sizes: ["36", "38", "40", "42"], colors: ["Verde", "Caqui", "Cinza", "Preto"] },
    { id: 3, name: "Moletom Graphic", price: 199.90, images: ["https://via.placeholder.com/400x400", "https://via.placeholder.com/400x400", "https://via.placeholder.com/400x400", "https://via.placeholder.com/400x400"], category: "roupas", sizes: ["P", "M", "G", "GG"], colors: ["Preto", "Cinza", "Azul", "Vermelho"] },
    { id: 4, name: "Tênis Urban", price: 399.90, images: ["https://via.placeholder.com/400x400", "https://via.placeholder.com/400x400", "https://via.placeholder.com/400x400", "https://via.placeholder.com/400x400"], category: "sapatos", sizes: ["37", "38", "39", "40"], colors: ["Branco", "Preto", "Cinza", "Azul"] },
  ];

  // Obter a categoria da URL
  useEffect(() => {
    const category = searchParams.get('category');
    if (category) {
      setSelectedCategory(category);
    } else {
      setSelectedCategory('all');
    }
  }, [searchParams]);

  // Filtrar produtos por categoria
  const filteredProducts = useMemo(() => {
    return selectedCategory === 'all'
      ? products
      : products.filter(product => product.category === selectedCategory);
  }, [products, selectedCategory]);

  // Calcular o número total de páginas
  const totalPages = useMemo(() => {
    return Math.ceil(filteredProducts.length / productsPerPage);
  }, [filteredProducts, productsPerPage]);

  // Obter os produtos da página atual
  const indexOfLastProduct = currentPage * productsPerPage;
  const indexOfFirstProduct = indexOfLastProduct - productsPerPage;
  const currentProducts = filteredProducts.slice(indexOfFirstProduct, indexOfLastProduct);

  // Funções de navegação de página
  const handlePrevPage = () => {
    if (currentPage > 1) {
      setCurrentPage(currentPage - 1);
    }
  };

  const handleNextPage = () => {
    if (currentPage < totalPages) {
      setCurrentPage(currentPage + 1);
    }
  };

  const handlePageClick = (page) => {
    setCurrentPage(page);
  };

  const handleCategoryChange = (e) => {
    setSelectedCategory(e.target.value);
    setCurrentPage(1); // Reseta a página para a primeira quando a categoria mudar
  };

  const handleProductClick = (product) => {
    setSelectedProduct(product);
    setShowModal(true);
  };

  const handleCloseModal = () => {
    setShowModal(false);
    setSelectedProduct(null);
  };

  return (
    <div className="min-h-screen bg-amber-50">
      <Header />

      <main className="max-w-7xl mx-auto px-4 py-8">
        {/* Cabeçalho com título e filtros */}
        <div className="flex justify-between items-center mb-8">
          <h1 className="text-3xl font-bold text-black">Coolmeia</h1>
          
          <div className="flex gap-4">
            {/* Dropdown de ordenação */}
            <div className="relative">
              <select 
                className="appearance-none bg-white px-4 py-2 pr-8 rounded-lg border border-amber-400 focus:outline-none focus:ring-2 focus:ring-amber-400"
                value={sortBy}
                onChange={(e) => setSortBy(e.target.value)}
              >
                <option value="newest">Mais Recentes</option>
                <option value="price-asc">Menor Preço</option>
                <option value="price-desc">Maior Preço</option>
                <option value="name">Nome</option>
              </select>
              <ChevronDown className="absolute right-2 top-1/2 transform -translate-y-1/2 text-amber-600 w-5 h-5 pointer-events-none" />
            </div>

            {/* Dropdown de filtro por categoria */}
            <div className="relative">
              <select
                className="appearance-none bg-white px-4 py-2 pr-8 rounded-lg border border-amber-400 focus:outline-none focus:ring-2 focus:ring-amber-400"
                value={selectedCategory}
                onChange={handleCategoryChange}
              >
                <option value="all">Todas as Categorias</option>
                <option value="roupas">Roupas</option>
                <option value="sapatos">Sapatos</option>
              </select>
              <ChevronDown className="absolute right-2 top-1/2 transform -translate-y-1/2 text-amber-600 w-5 h-5 pointer-events-none" />
            </div>

            {/* Botão de filtros */}
            <button className="flex items-center gap-2 bg-black text-amber-400 px-4 py-2 rounded-lg hover:bg-gray-800 transition-colors">
              <SlidersHorizontal className="w-5 h-5" />
              Filtros
            </button>
          </div>
        </div>

        {/* Grid de produtos */}
        <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-6">
          {currentProducts.map((product) => (
            <div 
              key={product.id} 
              className="bg-white rounded-lg shadow-md overflow-hidden border-2 border-amber-400 hover:border-black transition-colors duration-300 cursor-pointer"
              onClick={() => handleProductClick(product)}
            >
              <img
                src={product.images[0]}
                alt={product.name}
                className="w-full h-48 object-cover"
              />
              <div className="p-4">
                <h3 className="font-medium text-black">{product.name}</h3>
                <p className="text-lg font-bold text-amber-600 mt-1">
                  R$ {product.price.toFixed(2)}
                </p>
              </div>
            </div>
          ))}
        </div>

        {/* Paginação */}
        <div className="flex justify-center mt-8 gap-2">
          <button
            className={`px-4 py-2 border rounded-lg text-black hover:bg-amber-400 hover:text-white transition-colors ${currentPage === 1 ? 'border-amber-400 cursor-not-allowed' : 'border-amber-400'}`}
            onClick={handlePrevPage}
            disabled={currentPage === 1}
          >
            <ChevronLeft className="w-5 h-5" />
          </button>
          {Array.from({ length: totalPages }, (_, index) => index + 1).map((page) => (
            <button
              key={page}
              className={`px-4 py-2 rounded-lg ${currentPage === page ? 'bg-black text-amber-400' : 'border border-amber-400 text-black hover:bg-amber-400 hover:text-white transition-colors'}`}
              onClick={() => handlePageClick(page)}
            >
              {page}
            </button>
          ))}
          <button
            className={`px-4 py-2 border rounded-lg text-black hover:bg-amber-400 hover:text-white transition-colors ${currentPage === totalPages ? 'border-amber-400 cursor-not-allowed' : 'border-amber-400'}`}
            onClick={handleNextPage}
            disabled={currentPage === totalPages}
          >
            <ChevronRight className="w-5 h-5" />
          </button>
        </div>

        {/* Modal de detalhes do produto */}
        <Dialog open={showModal} onClose={handleCloseModal}>
          <DialogContent>
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-4">
                {selectedProduct?.images.map((image, index) => (
                  <img key={index} src={image} alt={selectedProduct.name} className="w-full h-auto rounded-lg" />
                ))}
              </div>
              <div>
                <DialogTitle>{selectedProduct?.name}</DialogTitle>
                <p className="text-lg font-bold text-amber-600 mt-2">
                  R$ {selectedProduct?.price.toFixed(2)}
                </p>
                <div className="mt-4">
                  <p className="font-medium">Tamanho:</p>
                  <div className="flex gap-2 mt-2">
                    {selectedProduct?.sizes.map((size, index) => (
                      <button
                        key={index}
                        className="px-4 py-2 border rounded-lg hover:bg-amber-400 hover:text-white transition-colors"
                      >
                        {size}
                      </button>
                    ))}
                  </div>
                </div>
                <div className="mt-4">
                  <p className="font-medium">Cor:</p>
                  <div className="flex gap-2 mt-2">
                    {selectedProduct?.colors.map((color, index) => (
                      <button
                        key={index}
                        className="px-4 py-2 border rounded-lg hover:bg-amber-400 hover:text-white transition-colors"
                      >
                        {color}
                      </button>
                    ))}
                  </div>
                </div>
                <button className="bg-black text-amber-400 px-4 py-2 rounded-lg mt-6 hover:bg-gray-800 transition-colors">
                  Adicionar ao Carrinho
                </button>
              </div>
            </div>
          </DialogContent>
        </Dialog>
      </main>

      <Footer />
    </div>
  );
};

export default AllProductsPage;
